t.script:
(function(){
var
H='display:none!important;height:0!important;overflow:hidden!important;visibility:hidden!important;';
var S=['body>header','#wrapwrap>header','header#top','header.o_top_fixed_element',
'.o_top_fixed_element','nav.o_main_navbar','.o_main_navbar','#oe_main_menu_navbar',
'.o_website_top_navbar','.o_website_top_navbar_container','.o_header_standard',
'body>footer','#wrapwrap>footer','footer#bottom','footer.o_footer','.o_footer','#footer',
'#oe_snippets','.o_we_website_top_actions'];
function
kill(){S.forEach(function(s){try{document.querySelectorAll(s).forEach(function(el){if(el.id!=='df-wrap'&&!el.closest('#df-wrap')){el.style.cssText=H;}});}catch(e){}});
var w=document.getElementById('wrapwrap');if(w){w.style.paddingTop='0';w.style.marginTop='0';}
document.body.style.paddingTop='0';document.body.style.marginTop='0';}
kill();
document.addEventListener('DOMContentLoaded',kill);
window.addEventListener('load',kill);
if(window.MutationObserver){var mo=new
MutationObserver(kill);mo.observe(document.documentElement,{childList:true,subtree:true});setTimeout(function(){mo.disconnect();},8000);}
})();
